import React from "react";

import { PageHeader, type PageHeaderProps } from "./PageHeader.js";
import styles from "./PageTemplate.module.css";

interface SubTab {
  id: string;
  label: string;
}

export interface PageTemplateProps
  extends Pick<
    PageHeaderProps,
    | "title"
    | "description"
    | "icon"
    | "onBack"
    | "onSettings"
    | "brand"
    | "onBrandClick"
    | "onViewerToggle"
    | "viewerVisible"
  > {
  actions?: React.ReactNode;
  extra?: React.ReactNode;
  className?: string;
  subTabs?: SubTab[];
  activeSubTab?: string;
  onSubTabChange?: (tabId: string) => void;
  children?: React.ReactNode;
  loading?: boolean;
  showTitle?: boolean;
  brandTitle?: string;
  brandAriaLabel?: string;
  viewerShowLabel?: string;
  viewerHideLabel?: string;
}

export function PageTemplate({
  title,
  actions,
  extra,
  description,
  icon,
  subTabs,
  activeSubTab,
  onSubTabChange,
  onBack,
  onSettings,
  brand,
  onBrandClick,
  onViewerToggle,
  viewerVisible,
  brandTitle,
  brandAriaLabel,
  viewerShowLabel,
  viewerHideLabel,
  children,
  loading,
  showTitle = true,
  className = "",
}: PageTemplateProps) {
  const headerExtra = extra ?? actions;

  return (
    <div className={`${styles.root} ${className}`.trim()}>
      {showTitle ? (
        <div className={styles.header}>
          <PageHeader
            title={title}
            description={description}
            icon={icon}
            extra={headerExtra}
            onBack={onBack}
            onSettings={onSettings}
            brand={brand}
            onBrandClick={onBrandClick}
            brandTitle={brandTitle}
            brandAriaLabel={brandAriaLabel}
            onViewerToggle={onViewerToggle}
            viewerVisible={viewerVisible}
            viewerShowLabel={viewerShowLabel}
            viewerHideLabel={viewerHideLabel}
          />
        </div>
      ) : null}

      {subTabs?.length ? (
        <div className={styles.subTabs} role="tablist" aria-label={`${title} sections`}>
          {subTabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => onSubTabChange?.(tab.id)}
              className={`${styles.subTabButton} ${activeSubTab === tab.id ? styles.subTabButtonActive : ""}`.trim()}
              type="button"
              role="tab"
              aria-selected={activeSubTab === tab.id}
            >
              {tab.label}
            </button>
          ))}
        </div>
      ) : null}

      <div className={styles.content}>
        {loading ? <div className={styles.loading}>Loading...</div> : children ?? null}
      </div>
    </div>
  );
}

.root {
  display: flex;
  flex-direction: column;
}

.header {
  flex-shrink: 0;
  position: sticky;
  top: 0;
  z-index: 10;
}

.subTabs {
  display: flex;
  gap: 4px;
  padding: 0 24px 16px;
  border-bottom: 1px solid var(--border-color);
  flex-shrink: 0;
}

.subTabButton {
  padding: 10px 16px;
  background: transparent;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-secondary);
  cursor: pointer;
  font-size: 13px;
  font-family: var(--font-mono);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  transition: all var(--transition-fast);
}

.subTabButtonActive {
  border-bottom-color: var(--accent-primary);
  color: var(--text-primary);
  font-weight: 800;
}

.content {
  display: flex;
  flex-direction: column;
  padding: 1.5rem;
}

.loading {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 60px;
  color: var(--text-secondary);
}
